/** Parser for Assignment 2 */

import java.io.*;
import java.util.*;

/** Exception class for representing parsing errors. */
class ParseException extends RuntimeException {
  ParseException(String s) { super(s); }
}

/** A parser class for Jam.  Each program requires a separate parser object. */
class Parser {
  
  private Lexer in;
  
  Parser(Lexer i) {
    in = i;
  }
  
  Parser(Reader inputStream) { this(new Lexer(inputStream)); }
  
  Parser(String fileName) throws IOException { this(new FileReader(fileName)); }
  
  Lexer lexer() { return in; }

  /** Parses a Jam program which is simply an expression (Exp) */
  public AST parse() throws ParseException {
    AST ast = parseExp();
    Token token = in.readToken();
    if (token != null) {
      throw error("unexpected token after complete expression: " + token);
    }
    return ast;
  }
  
  /** Parses:
    *   <exp> :: = if <exp> then <exp> else <exp>
    *            | let <prop-def-list> in <exp>
    *            | map <id-list> to <exp>
    *            | <term> { <biop> <term> }*  // (left associatively!)
    */
  private AST parseExp() {
    Token token = in.peek();
    if (token == Lexer.IF) return parseIf();
    if (token == Lexer.LET) return parseLet();
    if (token == Lexer.MAP) return parseMap();

    AST exp = parseTerm();
    while (isBinaryOp(in.peek())) {
      BinOp op = ((OpToken) in.readToken()).toBinOp();
      AST rhs = parseTerm();
      exp = new BinOpApp(op, exp, rhs);
    }
    return exp;
  }

  /* Many more parse methods follow.  I suggest defining separate parse methods for parsing
     Term, If, Map, and Let as shown in the syntax diagrams.  You will need additional
     methods for select contructions.  Let the syntax diagrams and your personal program
     design taste be your guide.  Avoid repeating code patterns. */

  /** Parses:
    *   <term> ::= <unop> <term>
    *            | <factor> { ( <exp-list> ) }*
    *            | empty
    *            | Int
    *            | Bool
    */
  private AST parseTerm() {
    Token token = in.peek();

    if (isUnaryOp(token)) {
      UnOp op = ((OpToken) in.readToken()).toUnOp();
      return new UnOpApp(op, parseTerm());
    }

    AST term = parseAtomicTerm();
    while (in.peek() == LeftParen.ONLY) {
      in.readToken();
      AST[] args = parseExpList();
      expect(RightParen.ONLY);
      term = new App(term, args);
    }
    return term;
  }

  /** Parses a non-unary term head: constants, identifiers, primitives, or parenthesized expressions. */
  private AST parseAtomicTerm() {
    Token token = in.peek();

    if (token == null) throw error("unexpected end of input");

    if (token instanceof IntConstant ||
        token instanceof BoolConstant ||
        token == EmptyConstant.ONLY ||
        token instanceof Variable ||
        token instanceof PrimFun) {
      return (AST) in.readToken();
    }

    if (token == LeftParen.ONLY) {
      in.readToken();
      AST exp = parseExp();
      expect(RightParen.ONLY);
      return exp;
    }

    throw error("expected a term but found " + token);
  }

  /** Parses:
    *   if <exp> then <exp> else <exp>
    */
  private AST parseIf() {
    expect(Lexer.IF);
    AST test = parseExp();
    expect(Lexer.THEN);
    AST conseq = parseExp();
    expect(Lexer.ELSE);
    AST alt = parseExp();
    return new If(test, conseq, alt);
  }

  /** Parses:
    *   let <def>+ in <exp>
    */
  private AST parseLet() {
    expect(Lexer.LET);
    List<Def> defs = new ArrayList<Def>();
    defs.add(parseDef());
    while (in.peek() instanceof Variable) {
      defs.add(parseDef());
    }
    expect(Lexer.IN);
    return new Let(defs.toArray(new Def[defs.size()]), parseExp());
  }

  /** Parses:
    *   map <id-list> to <exp>
    */
  private AST parseMap() {
    expect(Lexer.MAP);
    Variable[] vars = parseIdList();
    expect(Lexer.TO);
    return new Map(vars, parseExp());
  }

  /** Parses:
    *   <def> ::= Id := <exp> ;
    */
  private Def parseDef() {
    Token token = in.readToken();
    if (!(token instanceof Variable)) {
      throw error("expected identifier in definition but found " + token);
    }
    expect(Lexer.BIND);
    AST rhs = parseExp();
    expect(SemiColon.ONLY);
    return new Def((Variable) token, rhs);
  }

  /** Parses:
    *   <exp-list> ::= empty | <exp> { , <exp> }*
    * with ')' marking the empty case.
    */
  private AST[] parseExpList() {
    List<AST> exps = new ArrayList<AST>();
    if (in.peek() == RightParen.ONLY) {
      return new AST[0];
    }

    exps.add(parseExp());
    while (in.peek() == Comma.ONLY) {
      in.readToken();
      exps.add(parseExp());
    }
    return exps.toArray(new AST[exps.size()]);
  }

  /** Parses:
    *   <id-list> ::= empty | Id { , Id }*
    * with 'to' marking the empty case.
    */
  private Variable[] parseIdList() {
    List<Variable> vars = new ArrayList<Variable>();
    if (in.peek() == Lexer.TO) {
      return new Variable[0];
    }

    Token token = in.readToken();
    if (!(token instanceof Variable)) {
      throw error("expected identifier in map parameter list but found " + token);
    }
    vars.add((Variable) token);

    while (in.peek() == Comma.ONLY) {
      in.readToken();
      token = in.readToken();
      if (!(token instanceof Variable)) {
        throw error("expected identifier after ',' but found " + token);
      }
      vars.add((Variable) token);
    }
    return vars.toArray(new Variable[vars.size()]);
  }

  /** Consumes the expected token or throws a ParseException. */
  private void expect(Token expected) {
    Token actual = in.readToken();
    if (actual != expected) {
      throw error("expected " + expected + " but found " + actual);
    }
  }

  /** Returns true iff token is a legal unary operator in Assignment 1 Jam. */
  private boolean isUnaryOp(Token token) {
    return token instanceof OpToken && ((OpToken) token).isUnOp();
  }

  /** Returns true iff token is a legal binary operator in Assignment 1 Jam. */
  private boolean isBinaryOp(Token token) {
    return token instanceof OpToken && ((OpToken) token).isBinOp();
  }

  /** Constructs a ParseException with a consistent prefix. */
  private ParseException error(String message) {
    return new ParseException(message);
  }
}

import java.io.StringReader;

import junit.framework.TestCase;

public class ParserAgentTest extends TestCase {

  private void checkParse(String program, String expected) {
    Parser parser = new Parser(new StringReader(program));
    assertEquals(expected, parser.parse().toString());
  }

  private void checkParseError(String program) {
    Parser parser = new Parser(new StringReader(program));
    try {
      parser.parse();
      fail("expected ParseException for: " + program);
    } catch (ParseException e) {
      // expected
    }
  }

  public void testLeftAssociativeBinaryChain() {
    checkParse("1 - 2 - 3", "((1 - 2) - 3)");
  }

  public void testUnaryAndApplication() {
    checkParse("~f(1, 2)", "~ f(1, 2)");
  }

  public void testNestedApplicationUsesParenthesizedRator() {
    checkParse("(map x to x)(3)", "(map x to x)(3)");
  }

  public void testIfExpression() {
    checkParse("if true then 1 else 2", "if true then 1 else 2");
  }

  public void testLetExpressionWithMultipleDefs() {
    checkParse("let x := 1; y := x; in x + y", "let x := 1; y := x; in (x + y)");
  }

  public void testMapWithEmptyParameterList() {
    checkParse("map to 5", "map  to 5");
  }

  public void testPrimitiveApplicationWithNoArguments() {
    checkParse("cons()", "cons()");
  }

  public void testRejectTrailingTokens() {
    checkParseError("1 2");
  }

  public void testRejectMissingSemicolonInLet() {
    checkParseError("let x := 1 in x");
  }

  public void testRejectBracketSyntax() {
    checkParseError("[1]");
  }
}

